async (params, browser) => {
  // Open eBay deals page
  await browser.open('https://www.ebay.com/deals')

  // Wait for deals to load
  await browser.waitForSelector('.dne-itemtile, .ebayui-dne-item-featured-card, .ebayui-dne-item-pattern-card, [class*=\'deal-card\'], [data-testid=\'item-card\']', 15000)

  // Let deals page fully render
  await browser.wait(3000)

  // Scroll to load more deals
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(2000)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(2000)

  // Scroll for even more deals
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(2000)

  // Extract current deals
  const deals_data = await browser.evaluate(`const deals = []; const dealCards = document.querySelectorAll('.dne-itemtile, .ebayui-dne-item-featured-card, .ebayui-dne-item-pattern-card, [class*="deal-card"], [data-testid="item-card"], .dne-itemtile-detail'); dealCards.forEach(function(el, idx) { if (idx >= 20) return; const titleEl = el.querySelector('.dne-itemtile-title a, .ebayui-dne-item-featured-card__title a, [class*="item-title"] a, a.dne-itemtile-title, h3 a, .s-item__title'); const dealPriceEl = el.querySelector('.dne-itemtile-price .first, .dne-itemtile-price span, [class*="deal-price"], .s-item__price'); const originalPriceEl = el.querySelector('.dne-itemtile-original-price span, .itemtile-price-strikethrough, [class*="original-price"], .s-item__price--original'); const discountEl = el.querySelector('.dne-itemtile-discount, [class*="discount-percentage"], .s-item__discount'); const imgEl = el.querySelector('img[src*="ebayimg.com"], .dne-itemtile-image img, img'); const linkEl = el.querySelector('a[href*="/itm/"], a[href*="ebay.com"], a.dne-itemtile-title'); const freeShippingEl = el.querySelector('.dne-itemtile-shipping, [class*="free-shipping"], .s-item__freeXDays'); const soldEl = el.querySelector('.dne-itemtile-quantity-sold, [class*="quantity-sold"]'); const url = linkEl ? (linkEl.href.startsWith('http') ? linkEl.href : 'https://www.ebay.com' + linkEl.getAttribute('href')) : ''; const title = titleEl ? titleEl.textContent.trim() : ''; if (title) { deals.push({ title: title.substring(0, 200), deal_price: dealPriceEl ? dealPriceEl.textContent.trim() : '', original_price: originalPriceEl ? originalPriceEl.textContent.trim() : '', discount: discountEl ? discountEl.textContent.trim() : '', free_shipping: !!freeShippingEl, sold: soldEl ? soldEl.textContent.trim() : '', image: imgEl ? imgEl.getAttribute('src') : '', url: url }); } }); return { deal_count: deals.length, deals: deals, scraped_at: new Date().toISOString() }`)

  return deals_data
}
